# --- Convert a normal number into a Cistercian number ---
pattern = ' A B \nCD|FG\n I|K \nMN|PQ\n R S '
'''
 A B 
CD|FG
 I|K 
MN|PQ
 R S 
'''

units = {
    1:'B _',
    2:'F _',
    3:'F \\',
    4:'F /',
    5:'BF _/',
    6:'G |',
    7:'BG _|',
    8:'FG _|',
    9:'BFG __|'
}

replace = lambda s,a,b:s.translate(str.maketrans(a,b))

tens = {k*10:replace(v,'BFG/\\','ADC\\/') for k,v in units.items()}
hundreds = {k*100:replace(v,'BFG/\\','PKQ\\/') for k,v in units.items()}
thousands = {k*1000:replace(v,'BFG','NIM') for k,v in units.items()}

data_ntc = {**units,**tens,**hundreds,**thousands,300:'P /',400:'P \\',500:'PS \\вҖҫ',3000:'N \\',4000:'N /',5000:'NR /вҖҫ'}

def convert_ntc(n):
  if not 0<n<1e4:return ''
  s=pattern
  for x in [n//1e3*1e3,n//100%10*100,n//10%10*10,n%10]:
    if x:
      a,b=data_ntc[x].split()
      s=replace(s,a,b)
  r = ''.join(c if c in '\n_вҖҫ|/\\' else ' ' for c in s)
  return [l for l in r.split('\n')]



# --- Convert a Cistercian number into a normal number ---
units = {'B _':1,'F _':2,'F \\':3,'F /':4,'G |':6}

replace = lambda s,a,b:s.translate(str.maketrans(a,b))

tens = {replace(k,'BFG/\\','ADC\\/'):v*10 for k,v in units.items()}
hundreds = {replace(k,'BFG/\\','PKQ\\/'):v*100 for k,v in units.items()}
thousands = {replace(k,'BFG','NIM'):v*1000 for k,v in units.items()}

data_ctn = {**units,**tens,**hundreds,**thousands,'P /':300,'P \\':400,'S вҖҫ':100,'N \\':3000,'N /':4000,'R вҖҫ':1000}
data_i = {(0,3):'B',(1,3):'F',(1,4):'G',(0,1):'A',(1,0):'C',(1,1):'D',(2,3):'K',(3,3):'P',(3,4):'Q',(4,3):'S',(2,1):'I',(3,0):'M',(3,1):'N',(4,1):'R'}

def convert_ctn(n):
  return sum(data_ctn.get(f'{data_i[(y,x)]} {c}',0) for y,l in enumerate(n) for x,c in enumerate(l) if (y,x) in data_i)



# --- Solve ---
num_1 = [input() for _ in range(5)]
num_2 = [input() for _ in range(5)]

A = convert_ctn(num_1)
B = convert_ctn(num_2)
for l in convert_ntc(A+B):
    print(l)
